import React, { useState } from "react";
import FancyCarousel from "react-fancy-circular-carousel";
import 'react-fancy-circular-carousel/FancyCarousel.css';
import './style.css';

export default function App() {
  const images = [
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/insurance.svg",
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/apple-1.svg",
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/circle-dollar.svg",
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/train.svg",
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/gift-box-heart.svg",
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/heart-care.svg",
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/pig-piggy-bank.svg",
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/insurance.svg",
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/apple-1.svg",
    "http://dev.sterlingadministration.com/wp-content/uploads/2024/07/circle-dollar.svg"
  ];

  // const [focusElement, setFocusElement] = useState(0);
  const boxShadow = "0 0 20px 2px rgba(0,0,0,0.1)";


  return (
    <div className="reviews">
      <FancyCarousel
        images={images}
        // setFocusElement={setFocusElement}
        focusElementStyling={{ border: '2px solid #ba4949' }}
        autoRotateTime={3}
        centralImageBoxShadow={boxShadow}
        peripheralImageBoxShadow={boxShadow}
        border={false}
        transitionTime={3}
        offsetAngle={270}
        carouselRadius = {400}
      />
      <div className="data">
        <div className="text">
      Lorem ipsum dolor sit amet, consectetur adipisicing elit. Iste ad at consequatur consequuntur! Deleniti, hic. Ea dolorum nihil non maxime, nobis facilis voluptates, illum consectetur dolorem tempora rerum! Officiis dolore assumenda omnis sed quaerat, minus, impedit voluptas aperiam ducimus recusandae repellat alias explicabo sequi quo architecto consectetur ipsum accusamus officia.
        </div>
        <div className="name">
          John Doe | Google
        </div>
      </div>
    </div>
  );
}
